import base64
from pathlib import Path
from openai import OpenAI

client = OpenAI()

def extract_invoice_fields(pdf_page_path: str) -> dict:
    """Extract key fields from an invoice page using GPT-4o."""
    b64 = base64.b64encode(Path(pdf_page_path).read_bytes()).decode()
    ext = Path(pdf_page_path).suffix.lstrip(".")
    mime = {"jpg": "image/jpeg", "jpeg": "image/jpeg",
            "png": "image/png", "pdf": "application/pdf"}.get(ext, "image/png")

    response = client.chat.completions.create(
        model="gpt-4o",
        messages=[
            {
                "role": "system",
                "content": (
                    "You are a document extraction assistant. "
                    "Return only a JSON object with no markdown fences."
                ),
            },
            {
                "role": "user",
                "content": [
                    {
                        "type": "image_url",
                        "image_url": {
                            "url": f"data:{mime};base64,{b64}",
                            "detail": "high",
                        },
                    },
                    {
                        "type": "text",
                        "text": (
                            "Extract the following fields from this invoice: "
                            "invoice_number, invoice_date, vendor_name, "
                            "line_items (list of {description, quantity, unit_price, total}), "
                            "subtotal, tax, total_amount, currency. "
                            "If a field is not present, set it to null."
                        ),
                    },
                ],
            },
        ],
        max_tokens=1024,
        response_format={"type": "json_object"},
    )
    import json
    return json.loads(response.choices[0].message.content)

result = extract_invoice_fields("invoice_page.png")
print(result)
